VALID_OPERATORS = {
    "eq": "=",
    "neq": "!=",
    "gt": ">",
    "gte": ">=",
    "lt": "<",
    "lte": "<=",
    "like": "ILIKE",
    "contains": "ILIKE",
    "starts_with": "ILIKE",
    "ends_with": "ILIKE",
    "in": "IN",
    "is_null": "IS NULL",
    "is_not_null": "IS NOT NULL",
    "fulltext": "@@",
}

VALID_SORT_DIRECTIONS = {"asc", "desc"}

MAX_LIMIT = 100
DEFAULT_LIMIT = 20


class SecureQueryBuilder:
    """
    Builds parameterized SQL queries using ONLY whitelisted tables, columns, and operators.

    SECURITY APPROACH:
    - Table names and column names are validated against a whitelist and injected
      using psycopg2.sql module (which handles identifier quoting).
    - All user-provided VALUES go through parameterized queries (%(name)s syntax).
    - Operators are validated against a whitelist and mapped to SQL operators.
    - LIMIT/OFFSET are cast to integers.
    - Sort fields and directions are validated against whitelists.
    """

    def __init__(self, entity_name):
        if entity_name not in SEARCHABLE_SCHEMA:
            raise ValueError(
                f"Unknown entity: {entity_name}. "
                f"Valid entities: {list(SEARCHABLE_SCHEMA.keys())}"
            )
        self.schema = SEARCHABLE_SCHEMA[entity_name]
        self.table_name = self.schema["table"]
        self.conditions = []
        self.params = {}
        self.param_counter = 0
        self.sort_clauses = []
        self.limit_val = DEFAULT_LIMIT
        self.offset_val = 0
        self.use_fulltext = False
        self.fulltext_query_param = None

    def _get_all_valid_fields(self):
        """Return all searchable fields for this entity."""
        return set(
            self.schema["text_fields"]
            + self.schema["numeric_fields"]
            + self.schema["boolean_fields"]
        )

    def _validate_field(self, field_name):
        """Validate field name against whitelist. Raises ValueError if invalid."""
        valid = self._get_all_valid_fields()
        if field_name not in valid:
            raise ValueError(
                f"Invalid field '{field_name}' for table '{self.table_name}'. "
                f"Valid fields: {sorted(valid)}"
            )

    def _validate_operator(self, operator):
        """Validate operator against whitelist."""
        if operator not in VALID_OPERATORS:
            raise ValueError(
                f"Invalid operator '{operator}'. "
                f"Valid operators: {sorted(VALID_OPERATORS.keys())}"
            )

    def _next_param_name(self):
        """Generate a unique parameter name to avoid collisions."""
        self.param_counter += 1
        return f"p{self.param_counter}"

    def add_filter(self, field_name, operator, value):
        """
        Add a filter condition. All values are parameterized.
        Field names and operators are validated against whitelists.
        """
        self._validate_field(field_name)
        self._validate_operator(operator)

        col = psql.Identifier(field_name)

        if operator in ("is_null", "is_not_null"):
            if operator == "is_null":
                self.conditions.append(
                    psql.SQL("{} IS NULL").format(col)
                )
            else:
                self.conditions.append(
                    psql.SQL("{} IS NOT NULL").format(col)
                )
            return self

        param_name = self._next_param_name()

        if operator == "contains":
            self.params[param_name] = f"%{value}%"
            self.conditions.append(
                psql.SQL("{} ILIKE {}").format(col, psql.Placeholder(param_name))
            )
        elif operator == "starts_with":
            self.params[param_name] = f"{value}%"
            self.conditions.append(
                psql.SQL("{} ILIKE {}").format(col, psql.Placeholder(param_name))
            )
        elif operator == "ends_with":
            self.params[param_name] = f"%{value}"
            self.conditions.append(
                psql.SQL("{} ILIKE {}").format(col, psql.Placeholder(param_name))
            )
        elif operator == "in":
            if not isinstance(value, (list, tuple)):
                raise ValueError("'in' operator requires a list of values")
            # Create individual parameters for each value in the IN clause
            placeholders = []
            for v in value:
                p = self._next_param_name()
                self.params[p] = v
                placeholders.append(psql.Placeholder(p))
            self.conditions.append(
                psql.SQL("{} IN ({})").format(
                    col, psql.SQL(", ").join(placeholders)
                )
            )
        elif operator == "fulltext":
            if field_name not in self.schema["fulltext_fields"]:
                raise ValueError(
                    f"Field '{field_name}' does not support fulltext search. "
                    f"Fulltext fields: {self.schema['fulltext_fields']}"
                )
            self.params[param_name] = value
            self.conditions.append(
                psql.SQL("to_tsvector('english', {}) @@ plainto_tsquery('english', {})").format(
                    col, psql.Placeholder(param_name)
                )
            )
        else:
            sql_op = VALID_OPERATORS[operator]
            self.params[param_name] = value
            self.conditions.append(
                psql.SQL("{} " + sql_op + " {}").format(col, psql.Placeholder(param_name))
            )

        return self

    def add_fulltext_search(self, query_text, fields=None):
        """
        Add a full-text search across multiple fields using PostgreSQL ts_vectors.
        """
        if fields is None:
            fields = self.schema["fulltext_fields"]
        else:
            for f in fields:
                if f not in self.schema["fulltext_fields"]:
                    raise ValueError(
                        f"Field '{f}' does not support fulltext search. "
                        f"Fulltext fields: {self.schema['fulltext_fields']}"
                    )

        if not fields:
            raise ValueError(f"No fulltext-searchable fields for table '{self.table_name}'")

        param_name = self._next_param_name()
        self.params[param_name] = query_text

        # Combine multiple fields into a single tsvector
        tsvectors = [
            psql.SQL("to_tsvector('english', COALESCE({}, ''))").format(psql.Identifier(f))
            for f in fields
        ]
        combined = psql.SQL(" || ").join(tsvectors)

        self.conditions.append(
            psql.SQL("({}) @@ plainto_tsquery('english', {})").format(
                combined, psql.Placeholder(param_name)
            )
        )

        self.use_fulltext = True
        self.fulltext_query_param = param_name

        return self

    def add_sort(self, field_name, direction="asc"):
        """Add sort clause. Field and direction are validated."""
        if field_name not in self.schema["sortable_fields"]:
            raise ValueError(
                f"Cannot sort by '{field_name}'. "
                f"Sortable fields: {self.schema['sortable_fields']}"
            )
        direction = direction.lower()
        if direction not in VALID_SORT_DIRECTIONS:
            raise ValueError(f"Invalid sort direction '{direction}'. Use 'asc' or 'desc'.")

        dir_sql = psql.SQL("ASC" if direction == "asc" else "DESC")
        self.sort_clauses.append(
            psql.SQL("{} {}").format(psql.Identifier(field_name), dir_sql)
        )
        return self

    def set_pagination(self, limit=None, offset=None):
        """Set pagination. Values are cast to int for safety."""
        if limit is not None:
            self.limit_val = min(int(limit), MAX_LIMIT)
        if offset is not None:
            self.offset_val = max(int(offset), 0)
        return self

    def build_count_query(self):
        """Build a COUNT query for total results."""
        query = psql.SQL("SELECT COUNT(*) as total FROM {}").format(
            psql.Identifier(self.table_name)
        )
        if self.conditions:
            query = psql.SQL("{} WHERE {}").format(
                query, psql.SQL(" AND ").join(self.conditions)
            )
        return query, self.params

    def build_query(self):
        """Build the final SELECT query."""
        # Select clause - optionally include relevance score for fulltext
        if self.use_fulltext and self.fulltext_query_param:
            fields_for_rank = self.schema["fulltext_fields"]
            tsvectors = [
                psql.SQL("to_tsvector('english', COALESCE({}, ''))").format(psql.Identifier(f))
                for f in fields_for_rank
            ]
            combined = psql.SQL(" || ").join(tsvectors)
            select_clause = psql.SQL("SELECT *, ts_rank({}, plainto_tsquery('english', {})) AS relevance FROM {}").format(
                combined,
                psql.Placeholder(self.fulltext_query_param),
                psql.Identifier(self.table_name),
            )
        else:
            select_clause = psql.SQL("SELECT * FROM {}").format(
                psql.Identifier(self.table_name)
            )

        query = select_clause

        # WHERE clause
        if self.conditions:
            query = psql.SQL("{} WHERE {}").format(
                query, psql.SQL(" AND ").join(self.conditions)
            )

        # ORDER BY clause
        if self.sort_clauses:
            query = psql.SQL("{} ORDER BY {}").format(
                query, psql.SQL(", ").join(self.sort_clauses)
            )
        elif self.use_fulltext:
            query = psql.SQL("{} ORDER BY relevance DESC").format(query)
        else:
            default_sort = self.schema["default_sort"]
            query = psql.SQL("{} ORDER BY {} DESC").format(
                query, psql.Identifier(default_sort)
            )

        # LIMIT and OFFSET via parameters
        limit_param = self._next_param_name()
        offset_param = self._next_param_name()
        self.params[limit_param] = self.limit_val
        self.params[offset_param] = self.offset_val

        query = psql.SQL("{} LIMIT {} OFFSET {}").format(
            query,
            psql.Placeholder(limit_param),
            psql.Placeholder(offset_param),
        )

        return query, self.params


