# --- Helper to execute search ---

def execute_search(entity_name, filters, fulltext_query, fulltext_fields, sort, limit, offset):
    """Execute a search query and return results with pagination info."""
    builder = SecureQueryBuilder(entity_name)

    # Add fulltext search if provided
    if fulltext_query:
        ft_fields = fulltext_fields if fulltext_fields else None
        builder.add_fulltext_search(fulltext_query, ft_fields)

    # Add filters
    if filters:
        for f in filters:
            if f.operator == "in":
                val = f.values if f.values else []
                builder.add_filter(f.field, f.operator, val)
            else:
                val = f.value
                # Try to convert numeric values
                if f.field in SEARCHABLE_SCHEMA[entity_name]["numeric_fields"]:
                    try:
                        if "." in str(val):
                            val = float(val)
                        else:
                            val = int(val)
                    except (ValueError, TypeError):
                        pass
                elif f.field in SEARCHABLE_SCHEMA[entity_name]["boolean_fields"]:
                    val = val.lower() in ("true", "1", "yes") if val else False
                builder.add_filter(f.field, f.operator, val)

    # Add sorting
    if sort:
        for s in sort:
            builder.add_sort(s.field, s.direction or "asc")

    # Set pagination
    builder.set_pagination(limit=limit, offset=offset)

    # Execute queries
    with get_db_connection() as conn:
        with get_db_cursor(conn) as cursor:
            # Get total count
            count_query, count_params = builder.build_count_query()
            cursor.execute(count_query, count_params)
            total = cursor.fetchone()["total"]

            # Get results
            query, params = builder.build_query()
            cursor.execute(query, params)
            rows = cursor.fetchall()

    actual_limit = min(int(limit) if limit else DEFAULT_LIMIT, MAX_LIMIT)
    actual_offset = max(int(offset) if offset else 0, 0)

    pagination = PaginationInfo(
        total=total,
        limit=actual_limit,
        offset=actual_offset,
        has_next=(actual_offset + actual_limit) < total,
        has_previous=actual_offset > 0,
    )

    return rows, pagination


