class Query(ObjectType):
    search_products = Field(
        ProductSearchResult,
        filters=List(SearchFilterInput),
        fulltext_query=String(description="Full-text search query string"),
        fulltext_fields=List(String, description="Specific fulltext fields to search"),
        sort=List(SortInput),
        limit=Int(default_value=DEFAULT_LIMIT),
        offset=Int(default_value=0),
        description="Search products with flexible filtering, full-text search, sorting, and pagination",
    )

    search_users = Field(
        UserSearchResult,
        filters=List(SearchFilterInput),
        fulltext_query=String(),
        fulltext_fields=List(String),
        sort=List(SortInput),
        limit=Int(default_value=DEFAULT_LIMIT),
        offset=Int(default_value=0),
        description="Search users with flexible filtering",
    )

    search_orders = Field(
        OrderSearchResult,
        filters=List(SearchFilterInput),
        fulltext_query=String(),
        fulltext_fields=List(String),
        sort=List(SortInput),
        limit=Int(default_value=DEFAULT_LIMIT),
        offset=Int(default_value=0),
        description="Search orders with flexible filtering",
    )

    searchable_fields = graphene.JSONString(
        entity=String(required=True),
        description="Get the searchable fields and their types for an entity",
    )

    def resolve_search_products(self, info, filters=None, fulltext_query=None,
                                 fulltext_fields=None, sort=None, limit=DEFAULT_LIMIT, offset=0):
        try:
            rows, pagination = execute_search(
                "products", filters, fulltext_query, fulltext_fields, sort, limit, offset
            )
            items = [ProductType(**dict(row)) for row in rows]
            return ProductSearchResult(items=items, pagination=pagination)
        except ValueError as e:
            raise Exception(str(e))

    def resolve_search_users(self, info, filters=None, fulltext_query=None,
                              fulltext_fields=None, sort=None, limit=DEFAULT_LIMIT, offset=0):
        try:
            rows, pagination = execute_search(
                "users", filters, fulltext_query, fulltext_fields, sort, limit, offset
            )
            items = [UserType(**dict(row)) for row in rows]
            return UserSearchResult(items=items, pagination=pagination)
        except ValueError as e:
            raise Exception(str(e))

    def resolve_search_orders(self, info, filters=None, fulltext_query=None,
                               fulltext_fields=None, sort=None, limit=DEFAULT_LIMIT, offset=0):
        try:
            rows, pagination = execute_search(
                "orders", filters, fulltext_query, fulltext_fields, sort, limit, offset
            )
            items = [OrderType(**dict(row)) for row in rows]
            return OrderSearchResult(items=items, pagination=pagination)
        except ValueError as e:
            raise Exception(str(e))

    def resolve_searchable_fields(self, info, entity):
        if entity not in SEARCHABLE_SCHEMA:
            raise Exception(f"Unknown entity: {entity}. Valid: {list(SEARCHABLE_SCHEMA.keys())}")
        schema = SEARCHABLE_SCHEMA[entity]
        return {
            "entity": entity,
            "text_fields": schema["text_fields"],
            "numeric_fields": schema["numeric_fields"],
            "boolean_fields": schema["boolean_fields"],
            "fulltext_fields": schema["fulltext_fields"],
            "sortable_fields": schema["sortable_fields"],
            "supported_operators": list(VALID_OPERATORS.keys()),
            "max_limit": MAX_LIMIT,
        }


